// Pull both per-index ensures-foralls into scope so triggers line up for
// both post1_self_ and post2_self_; z3 otherwise instantiates only one.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Pointwise page-by-page equality between the two runs.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // At i == index, every Page field of post1 and post2 equals the
        // corresponding pre_self_ field (rev_pointer equals `rev_pointer`
        // in both runs), so the structs are field-wise equal.
        assert(post1_self_.page_array@[i].addr
            =~= post2_self_.page_array@[i].addr);
        assert(post1_self_.page_array@[i].state
            =~= post2_self_.page_array@[i].state);
        assert(post1_self_.page_array@[i].is_io_page
            =~= post2_self_.page_array@[i].is_io_page);
        assert(post1_self_.page_array@[i].ref_count
            =~= post2_self_.page_array@[i].ref_count);
        assert(post1_self_.page_array@[i].owning_container
            =~= post2_self_.page_array@[i].owning_container);
        assert(post1_self_.page_array@[i].mappings
            =~= post2_self_.page_array@[i].mappings);
        assert(post1_self_.page_array@[i].io_mappings
            =~= post2_self_.page_array@[i].io_mappings);
        assert(post1_self_.page_array@[i].rev_pointer
            =~= post2_self_.page_array@[i].rev_pointer);
    } else {
        // At i != index, both posts agree with pre_self_, hence with each other.
        assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
    }
}

// Seq extensionality lifts pointwise equality to a view-level equality.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);

// All non-page_array modified fields are equal to pre_self_'s in both
// runs by the ensures clauses, so they are equal to each other.
assert(post1_self_.free_pages_4k == post2_self_.free_pages_4k);
assert(post1_self_.free_pages_2m == post2_self_.free_pages_2m);
assert(post1_self_.free_pages_1g == post2_self_.free_pages_1g);
assert(post1_self_.allocated_pages_4k == post2_self_.allocated_pages_4k);
assert(post1_self_.allocated_pages_2m == post2_self_.allocated_pages_2m);
assert(post1_self_.allocated_pages_1g == post2_self_.allocated_pages_1g);
assert(post1_self_.mapped_pages_4k == post2_self_.mapped_pages_4k);
assert(post1_self_.mapped_pages_2m == post2_self_.mapped_pages_2m);
assert(post1_self_.mapped_pages_1g == post2_self_.mapped_pages_1g);
assert(post1_self_.page_perms_4k == post2_self_.page_perms_4k);
assert(post1_self_.page_perms_2m == post2_self_.page_perms_2m);
assert(post1_self_.page_perms_1g == post2_self_.page_perms_1g);
assert(post1_self_.container_map_4k == post2_self_.container_map_4k);
assert(post1_self_.container_map_2m == post2_self_.container_map_2m);
assert(post1_self_.container_map_1g == post2_self_.container_map_1g);
